firestore.rules:
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {
    function signedIn() { return request.auth != null; }
    match /users/{userId} {
      allow read: if signedIn();
      allow create, update: if signedIn() && request.auth.uid == userId;
    }
    match /rooms/{roomId} {
      allow read: if true;
      allow create: if signedIn() && request.resource.data.ownerId == request.auth.uid;
      allow update, delete: if signedIn() && resource.data.ownerId == request.auth.uid;
    }
    match /requests/{requestId} {
      allow create: if signedIn() && request.resource.data.seekerId == request.auth.uid;
      allow read, update: if signedIn() && (resource.data.seekerId == request.auth.uid || resource.data.ownerId == request.auth.uid);
    }
    match /chats/{chatId} {
      allow read, write: if signedIn() && request.auth.uid in resource.data.participants;
      match /messages/{messageId} {
        allow read, create: if signedIn();
      }
    }
  }
}

storage.rules:
rules_version = '2';
service firebase.storage {
  match /b/{bucket}/o {
    match /rooms/{allPaths=**} {
      allow read: if true;
      allow write: if request.auth != null && request.resource.size < 5 * 1024 * 1024 && request.resource.contentType.matches('image/.*');
    }
  }
}
